SELECT ?state (COUNT(?person) AS ?count) ?stateLabel WHERE {
  ?person p:P710 ?participant.
  ?participant ps:P710 wd:Q1644.
  ?participant pq:P3443 wd:Q134707.
  ?person wdt:P19 ?birthplace.
  ?birthplace wdt:P131 ?state.
  ?state wdt:P17 wd:Q30.
  OPTIONAL { ?state rdfs:label ?stateLabel FILTER (LANG(?stateLabel) = "en") }
} GROUP BY ?state ?stateLabel

